#ifndef GEMM_N4096_K4096_KERNEL_H_
#define GEMM_N4096_K4096_KERNEL_H_

#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdint.h>

cudaError_t gemm_n4096_k4096_launch(
    const half* A,   // [M,4096] row-major
    const half* B,   // [4096,4096] row-major, compute C = A * B^T
    half* C,         // [M,4096] row-major
    int M,
    cudaStream_t stream);

#endif  // GEMM_N4096_K4096_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <mma.h>

using namespace nvcuda;

namespace {

constexpr int N = 4096;
constexpr int K = 4096;

constexpr int WM = 16;
constexpr int WN = 16;
constexpr int WK = 16;

// Tile: 128x32 per block using 16 warps => 512 threads
// This matches the natural mapping: (BM/WM) * (BN/WN) warps.
constexpr int BM = 128;
constexpr int BN = 32;

constexpr int WARPS_M = BM / WM; // 8
constexpr int WARPS_N = BN / WN; // 2
constexpr int WARPS_PER_BLOCK = WARPS_M * WARPS_N; // 16
constexpr int THREADS = WARPS_PER_BLOCK * 32; // 512

static_assert(N % BN == 0, "N must be divisible by BN");
static_assert(K % WK == 0, "K must be divisible by WK");
static_assert(WARPS_PER_BLOCK == 16, "Unexpected warps per block");
static_assert(THREADS == 512, "Unexpected threads per block");

// B is row-major [N,K]. For C = A * B^T, we need B^T[k,n] = B[n,k].
// WMMA matrix_b col_major expects address of element (row=k, col=n) with leading dimension ldm = K.
// Using pointer &B[n*K + k] with ldm=K works.
__global__ void gemm_wmma_128x32(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int M)
{
#if __CUDA_ARCH__ < 700
  (void)A; (void)B; (void)C; (void)M;
  return;
#else
  const int tid = (int)threadIdx.x;
  const int warp_id = tid >> 5;   // 0..15
  const int lane = tid & 31;

  const int block_n = (int)blockIdx.x; // tiles of 32 cols
  const int block_m = (int)blockIdx.y; // tiles of 128 rows

  const int c_row0 = block_m * BM;
  const int c_col0 = block_n * BN;

  const int warp_m = warp_id / WARPS_N; // 0..7
  const int warp_n = warp_id % WARPS_N; // 0..1

  const int warp_row = c_row0 + warp_m * WM;
  const int warp_col = c_col0 + warp_n * WN;

  if (warp_row >= M) return;

  wmma::fragment<wmma::accumulator, WM, WN, WK, float> acc;
  wmma::fill_fragment(acc, 0.0f);

  const bool full_tile_m = (warp_row + (WM - 1) < M);

  // Shared memory for tail A tiles (only needed when M is not multiple of 16).
  // Layout: [WARPS_PER_BLOCK][WM*WK] half
  extern __shared__ half shA_tail[];
  half* a_tail_warp = shA_tail + warp_id * (WM * WK);

#pragma unroll 1
  for (int k0 = 0; k0 < K; k0 += WK) {
    wmma::fragment<wmma::matrix_a, WM, WN, WK, half, wmma::row_major> a_frag;
    wmma::fragment<wmma::matrix_b, WM, WN, WK, half, wmma::col_major> b_frag;

    if (full_tile_m) {
      const half* a_ptr = A + warp_row * K + k0;
      wmma::load_matrix_sync(a_frag, a_ptr, K);
    } else {
      // Zero-pad out-of-range rows for A
      for (int i = lane; i < WM * WK; i += 32) {
        const int r = i / WK;
        const int c = i - r * WK;
        const int gr = warp_row + r;
        const int gk = k0 + c;
        half v = __float2half(0.0f);
        if (gr < M) v = A[gr * K + gk];
        a_tail_warp[i] = v;
      }
      __syncwarp();
      wmma::load_matrix_sync(a_frag, a_tail_warp, WK);
    }

    const half* b_ptr = B + warp_col * K + k0;
    wmma::load_matrix_sync(b_frag, b_ptr, K);

    wmma::mma_sync(acc, a_frag, b_frag, acc);
  }

  // Store accumulator directly to global (row-major 16x16).
  // Use a float staging buffer only for tail-M to avoid writing invalid rows.
  if (full_tile_m) {
    half* c_ptr = C + warp_row * N + warp_col;
    wmma::store_matrix_sync(c_ptr, acc, N, wmma::mem_row_major);
  } else {
    // Use shared float buffer per warp: [WARPS_PER_BLOCK][WM*WN] float.
    // Place after A tail region. Ensure proper alignment to float.
    // We reuse dynamic shared memory by requiring it to be sized for both regions.
    // Compute float base pointer aligned up from shA_tail.
    uintptr_t base = reinterpret_cast<uintptr_t>(shA_tail);
    base += (size_t)WARPS_PER_BLOCK * (WM * WK) * sizeof(half);
    base = (base + alignof(float) - 1) & ~(uintptr_t)(alignof(float) - 1);
    float* shC = reinterpret_cast<float*>(base);

    float* cbuf = shC + warp_id * (WM * WN);
    wmma::store_matrix_sync(cbuf, acc, WN, wmma::mem_row_major);
    __syncwarp();

    half* c_ptr0 = C + warp_row * N + warp_col;
    for (int i = lane; i < WM * WN; i += 32) {
      const int r = i / WN;
      const int c = i - r * WN;
      const int gr = warp_row + r;
      if (gr < M) {
        c_ptr0[r * N + c] = __float2half_rn(cbuf[i]);
      }
    }
  }
#endif
}

} // namespace

cudaError_t gemm_n4096_k4096_launch(
    const half* A,
    const half* B,
    half* C,
    int M,
    cudaStream_t stream)
{
  if (!A || !B || !C) return cudaErrorInvalidDevicePointer;
  if (M <= 0) return cudaErrorInvalidValue;

  dim3 block(THREADS, 1, 1);
  dim3 grid(N / BN, (M + BM - 1) / BM, 1);

  // Dynamic shared memory:
  // A tail: WARPS_PER_BLOCK * WM*WK half
  // C buf : WARPS_PER_BLOCK * WM*WN float (only used for tail, but allocated always for simplicity)
  size_t shA = (size_t)WARPS_PER_BLOCK * (WM * WK) * sizeof(half);
  size_t shC = (size_t)WARPS_PER_BLOCK * (WM * WN) * sizeof(float);
  // Add padding for alignment of float region
  size_t shmem = shA + 16 + shC;

  gemm_wmma_128x32<<<grid, block, shmem, stream>>>(A, B, C, M);
  return cudaGetLastError();
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda.h>
#include <cuda_runtime.h>

#include <stdexcept>
#include <string>

#include "kernel.h"

static inline void checkCuda(cudaError_t err, const char* what) {
  if (err != cudaSuccess) {
    throw std::runtime_error(std::string(what) + ": " + cudaGetErrorString(err));
  }
}

torch::Tensor run(torch::Tensor A, torch::Tensor B, c10::optional<torch::Tensor> out_opt = c10::nullopt) {
  TORCH_CHECK(A.defined() && B.defined(), "A and B must be defined");
  TORCH_CHECK(A.dim() == 2, "A must be rank-2 [M, K]");
  TORCH_CHECK(B.dim() == 2, "B must be rank-2 [N, K]");

  if (!A.device().is_cuda()) A = A.to(torch::kCUDA);
  if (!B.device().is_cuda()) B = B.to(torch::kCUDA);

  TORCH_CHECK(A.device().is_cuda(), "A must be a CUDA tensor");
  TORCH_CHECK(B.device().is_cuda(), "B must be a CUDA tensor");
  TORCH_CHECK(A.dtype() == torch::kFloat16, "A must be float16");
  TORCH_CHECK(B.dtype() == torch::kFloat16, "B must be float16");

  const int64_t M64 = A.size(0);
  const int64_t K_A = A.size(1);
  const int64_t N64 = B.size(0);
  const int64_t K_B = B.size(1);

  TORCH_CHECK(K_A == 4096, "A.size(1) must be 4096, got ", K_A);
  TORCH_CHECK(N64 == 4096, "B.size(0) must be 4096, got ", N64);
  TORCH_CHECK(K_B == 4096, "B.size(1) must be 4096, got ", K_B);
  TORCH_CHECK(M64 >= 1, "M must be >= 1");
  TORCH_CHECK(M64 <= INT32_MAX, "M too large for int32");

  if (!A.is_contiguous()) A = A.contiguous();
  if (!B.is_contiguous()) B = B.contiguous();

  torch::Tensor C;
  if (out_opt.has_value() && out_opt.value().defined()) {
    C = out_opt.value();
    if (!C.device().is_cuda()) C = C.to(torch::kCUDA);
    TORCH_CHECK(C.device().is_cuda(), "out must be a CUDA tensor");
    TORCH_CHECK(C.dtype() == torch::kFloat16, "out must be float16");
    TORCH_CHECK(C.dim() == 2, "out must be rank-2 [M, N]");
    TORCH_CHECK(C.size(0) == M64 && C.size(1) == 4096,
                "out must have shape [", M64, ", 4096], got [", C.size(0), ", ", C.size(1), "]");
    if (!C.is_contiguous()) C = C.contiguous();
  } else {
    C = torch::empty({M64, 4096}, torch::TensorOptions().dtype(torch::kFloat16).device(A.device()));
  }

  const int M = (int)M64;

  const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr<at::Half>());
  const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr<at::Half>());
  half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  checkCuda(gemm_n4096_k4096_launch(A_ptr, B_ptr, C_ptr, M, stream),
            "gemm_n4096_k4096_launch failed");
  checkCuda(cudaGetLastError(), "post-launch cudaGetLastError failed");

  // Avoid device-wide sync; stream sync is enough for correctness in this extension.
  checkCuda(cudaStreamSynchronize(stream), "cudaStreamSynchronize failed");

  return C;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gemm_n4096_k4096: C = A * B^T (FP16 WMMA)");
}
